import sys
input = sys.stdin.readline

def solve():
    input()  # empty line
    m, n = map(int, input().split())
    p = []
    for _ in range(m):
        row = list(map(int, input().split()))
        p.append(row)

    # Collect all values for binary search
    vals = sorted(set(v for row in p for v in row))

    def check(alpha):
        # Condition 1: every friend j has some shop with p[i][j] >= alpha
        for j in range(n):
            if max(p[i][j] for i in range(m)) < alpha:
                return False
        # Condition 2: some shop covers >= 2 friends
        for i in range(m):
            cnt = sum(1 for j in range(n) if p[i][j] >= alpha)
            if cnt >= 2:
                return True
        return False

    lo, hi = 0, len(vals) - 1
    ans = 0
    while lo <= hi:
        mid = (lo + hi) // 2
        if check(vals[mid]):
            ans = vals[mid]
            lo = mid + 1
        else:
            hi = mid - 1
    print(ans)

t = int(input())
for _ in range(t):
    solve()

